        if (categoryFilter !== 'All') {
            defs = defs.filter(d => d.category === categoryFilter);
        }
        return defs.sort((a, b) => {
            const idxA = CATEGORY_ORDER.indexOf(a.category);
            const idxB = CATEGORY_ORDER.indexOf(b.category);
            const valA = idxA === -1 ? 999 : idxA;
            const valB = idxB === -1 ? 999 : idxB;
            if (valA !== valB) return valA - valB;
            return a.title.localeCompare(b.title);
        });
    }, [categoryFilter]);

    return (
        <>
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6 pb-12 animate-fade-in">
                {sortedDefinitions.map(def => {
                    const relevantReports = reports.filter(r => r['REPORT TYPE'] === def.id);
                    const isFullyCompliant = relevantReports.length > 0 && relevantReports.every(r => r.STATUS === 'Completed');

                    if (statusFilter === 'Completed' && !isFullyCompliant) return null;
                    if (statusFilter === 'Pending' && isFullyCompliant) return null;

                    return (
                        <ReportCard 
                            key={def.id} 
                            definition={def} 
                            reports={relevantReports} 
                            onNavigate={onNavigate} 
                            onViewPending={(list) => setModalData({ title: def.title, list })}
                        />
                    );
                })}
            </div>

            {modalData && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4 animate-fade-in">
                    <div className="bg-white rounded-2xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden border border-white/20">
                        <div className="px-8 py-6 border-b border-slate-100 bg-slate-50/80 flex justify-between items-center shrink-0">
                            <div>
                                <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Pending Submissions</h4>
                                <h3 className="font-extrabold text-slate-800 text-2xl tracking-tight leading-tight">{modalData.title}</h3>
                            </div>
                            <button onClick={() => setModalData(null)} className="text-slate-400 hover:text-slate-600 bg-white border border-slate-200 p-2 rounded-full transition-all shadow-sm">
                                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                                </svg>
                            </button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-6 bg-white">
                            {modalData.list.length > 0 ? (
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                                    {modalData.list.map((item, idx) => (
                                        <div key={idx} className="flex items-center text-slate-700 text-sm font-semibold p-3 rounded-xl bg-slate-50 border border-slate-100 hover:border-amber-200 hover:bg-amber-50 transition-colors group">
                                            <span className="flex items-center justify-center w-8 h-8 rounded-lg bg-white border border-slate-200 text-amber-600 mr-3 shrink-0 text-xs font-bold shadow-sm group-hover:border-amber-200">
                                                {idx + 1}
                                            </span>
                                            <span className="truncate" title={item}>{item}</span>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="flex flex-col items-center justify-center h-64 text-center px-6">
                                    <div className="w-20 h-20 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mb-6 shadow-sm border border-emerald-100">
                                        <CheckIcon />
                                    </div>
                                    <p className="text-emerald-700 font-extrabold text-2xl">All Compliant!</p>
                                </div>
