                                              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" /></svg>
                                          </div>
                                          <p className="text-sm font-bold text-blue-800">Showing <span className="underline">{statusFilter}</span> reports only</p>
                                      </div>
                                      <button onClick={() => setStatusFilter("All")} className="text-xs font-black uppercase text-blue-600 hover:text-blue-800 bg-white px-3 py-1.5 rounded-lg border border-blue-100 shadow-sm transition-all">Clear Filter</button>
