const ActionButton: React.FC<{ onClick: () => void, disabled?: boolean, status?: string }> = ({ onClick, disabled, status }) => {
    const isLate = status === 'Late';
    return (
        <button 
            onClick={onClick}
            disabled={disabled}
            className={`px-3 py-1.5 rounded-md transition-colors text-[10px] uppercase font-bold shadow-sm tracking-wide border ${
