                : 'bg-white text-blue-600 hover:text-blue-900 border-blue-300 hover:bg-blue-50'
            }`}
        >
            {disabled ? 'LOCKED' : isLate ? 'LATE UPDATE' : 'UPDATE'}
        </button>
    );
};

const StatusBadge: React.FC<{status: string, isOverdue?: boolean}> = ({ status, isOverdue }) => {
  let bgClass = 'bg-slate-100 text-slate-700 border-slate-200';
  let dotClass = 'bg-slate-400';
  let label = status;

  if (status === 'Completed') {
      bgClass = 'bg-emerald-50 text-emerald-700 border-emerald-200 ring-1 ring-emerald-600/20';
      dotClass = 'bg-emerald-500';
  } else if (status === 'Overdue' || status === 'Late') {
      bgClass = 'bg-rose-50 text-rose-700 border-rose-200 ring-1 ring-rose-600/20';
      dotClass = 'bg-rose-500 animate-pulse';
      label = status === 'Late' ? 'Late Submission' : 'Overdue';
  } else if (status === 'Pending') {
      bgClass = 'bg-amber-50 text-amber-700 border-amber-200 ring-1 ring-amber-600/20';
      dotClass = 'bg-amber-500';
  } else if (status === 'Partial') {
      bgClass = 'bg-orange-50 text-orange-700 border-orange-200 ring-1 ring-orange-600/20';
      dotClass = 'bg-orange-500';
  } else if (status === 'Waiting') {
      bgClass = 'bg-slate-50 text-slate-500 border-slate-200';
      dotClass = 'bg-slate-300';
      label = 'Not yet open';
  }

  return (
    <div className="flex flex-col items-start">
        <span className={`inline-flex items-center px-2.5 py-1 rounded-full text-xs font-bold border shadow-sm ${bgClass}`}>
            <span className={`mr-1.5 h-2 w-2 rounded-full ${dotClass}`}></span>
            {label}
        </span>
        {(isOverdue || status === 'Overdue' || status === 'Late') && (
            <span className="text-[10px] font-bold text-rose-500 mt-1 ml-1 flex items-center">
                <span className="mr-1">⚠️</span> Beyond deadline
            </span>
        )}
    </div>
  );
};

interface ReportsTableProps {
  reports: Report[];
  showActions?: boolean;
  onEdit?: (report: Report) => void;
}

export const ReportsTable: React.FC<ReportsTableProps> = ({ reports, showActions = true, onEdit }) => {
  const headers: (keyof Report)[] = ['LGU/BARANGAY', 'REPORT TYPE', 'FREQUENCY', 'STATUS', 'LAST UPDATED', 'DATA SUMMARY'];
  const handleDownloadPdf = () => {
    if (!(window as any).jspdf) return;
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF('l', 'mm', 'a4'); 
    const dateStr = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
    doc.setFontSize(12);
    doc.text("DILG-SAMAR", 148.5, 15, { align: 'center' }); 
    doc.setFontSize(11);
    doc.text(`Monitoring Dashboard as of ${dateStr}`, 148.5, 22, { align: 'center' });
    const pdfHeaders = headers.map(h => h);
    const data = reports.map(r => headers.map(h => r[h]));
    (doc as any).autoTable({ head: [pdfHeaders], body: data, startY: 30, styles: { fontSize: 8 }, headStyles: { fillColor: [30, 41, 59], textColor: 255 }, theme: 'grid' });
    doc.save(`Monitoring_Dashboard.pdf`);
  };
  const handleDownloadExcel = () => {
      if (typeof XLSX === 'undefined') { alert("Excel library missing"); return; }
      const excelHeaders = ['LGU/BARANGAY', 'REPORT TYPE', 'FREQUENCY', 'STATUS', 'LAST UPDATED', 'DATA SUMMARY'];
      const data = reports.map(r => excelHeaders.map(h => r[h as keyof Report]));
      const ws = XLSX.utils.aoa_to_sheet([excelHeaders, ...data]);
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "Dashboard");
      XLSX.writeFile(wb, `Monitoring_Dashboard.xlsx`);
  };
  if (reports.length === 0) return <EmptyState />;
  return (
    <div className="space-y-6 animate-fade-in">
       <div className="flex justify-end"><ExportMenu onExportPdf={handleDownloadPdf} onExportExcel={handleDownloadExcel} label="Export List" /></div>
        <div className="overflow-x-auto bg-white rounded-2xl shadow-md shadow-slate-200/50 border border-slate-200">
        <table className="min-w-full table-fixed divide-y divide-slate-100">
            <thead className="bg-slate-900 text-white">
            <tr>
                <th scope="col" className="w-[200px] px-6 py-5 text-left text-xs font-bold uppercase tracking-wider opacity-90">LGU/BARANGAY</th>
                <th scope="col" className="w-[150px] px-6 py-5 text-left text-xs font-bold uppercase tracking-wider opacity-90">REPORT TYPE</th>
