};

const DynamicReportTable: React.FC<DynamicReportTableProps> = ({ reports, definition, onEdit, isProvince }) => {
  const [lguFilter, setLguFilter] = useState<string>("All");

  const displayedReports = useMemo(() => {
      if (!isProvince || lguFilter === "All") return reports;
      return reports.filter(r => {
          const city = (r.details?.city || "").toUpperCase();
          return city === lguFilter.toUpperCase();
      });
  }, [reports, lguFilter, isProvince]);

  const handleDownloadPdf = () => {
      if (!(window as any).jspdf) return;
      const { jsPDF } = (window as any).jspdf;
      const doc = new jsPDF('l', 'mm', 'a4');
      const dateStr = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
      doc.setFontSize(12).text("DILG-SAMAR", 148.5, 15, { align: 'center' });

      const filterSuffix = isProvince && lguFilter !== "All" ? ` - ${lguFilter}` : "";
      doc.setFontSize(11).text(`Full Data Export: ${definition.title}${filterSuffix} as of ${dateStr}`, 148.5, 22, { align: 'center' });

      const headers = ['LGU/BARANGAY', ...definition.fields.map(f => f.label), 'STATUS', 'LAST UPDATED'];
      const data = displayedReports.map(report => {
          const row = [report['LGU/BARANGAY']];
          definition.fields.forEach(field => {
              let val = report.details?.[field.key];
              if (Array.isArray(val)) val = `${val.length} file(s) attached`;
              else if (typeof val === 'string' && val.startsWith('data:')) val = 'File Pending Upload';
              row.push(val || '');
          });
          row.push(report.STATUS);
          row.push(report['LAST UPDATED']);
          return row;
      });
      (doc as any).autoTable({ head: [headers], body: data, startY: 30, styles: { fontSize: 6, cellPadding: 1 }, headStyles: { fillColor: [30, 41, 59], textColor: 255 }, theme: 'grid' });
      doc.save(`${definition.title}${filterSuffix.replace(/\s+/g, '_')}_Export.pdf`);
  };

  const handleDownloadExcel = () => {
      if (typeof XLSX === 'undefined') return;
      const headers = ['LGU/BARANGAY', ...definition.fields.map(f => f.label), 'STATUS', 'LAST UPDATED'];
      const data = displayedReports.map(report => {
          const row = [report['LGU/BARANGAY']];
          definition.fields.forEach(field => {
              let val = report.details?.[field.key];
              if (Array.isArray(val)) val = val.join(', ');
              row.push(val || '');
          });
          row.push(report.STATUS);
          row.push(report['LAST UPDATED']);
          return row;
      });
      const ws = XLSX.utils.aoa_to_sheet([headers, ...data]);
      const wb = XLSX.utils.book_new();
      const filterSuffix = isProvince && lguFilter !== "All" ? `_${lguFilter}` : "";
      XLSX.utils.book_append_sheet(wb, ws, "Full Report Data");
      XLSX.writeFile(wb, `${definition.title}${filterSuffix.replace(/\s+/g, '_')}_Export.xlsx`);
  };

  const getHeaderStyle = () => {
    switch(definition.category) {
      case 'Monthly': return 'bg-gradient-to-r from-blue-700 to-blue-800';
      case 'Quarterly': return 'bg-gradient-to-r from-orange-600 to-orange-700';
      case 'Barangay': return 'bg-gradient-to-r from-indigo-600 to-indigo-800';
      default: return 'bg-gradient-to-r from-teal-700 to-teal-800';
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
        <ReportProgress reports={displayedReports} category={definition.category} />

        <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-white/50 p-4 rounded-2xl border border-slate-200">
            <div className="flex-1 w-full">
                {isProvince && (
                    <div className="flex items-center gap-3">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest whitespace-nowrap">Filter LGU Unit:</label>
                        <select 
                            value={lguFilter}
                            onChange={(e) => setLguFilter(e.target.value)}
                            className="bg-white border border-slate-200 rounded-xl px-4 py-2 text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500 transition-all min-w-[200px] shadow-sm"
                        >
                            <option value="All">All Samar LGUs</option>
                            {LGU_LIST.map(lgu => <option key={lgu} value={lgu}>{lgu}</option>)}
                        </select>
                    </div>
                )}
            </div>

            <div className="flex items-center gap-3">
                <ExportMenu onExportPdf={handleDownloadPdf} onExportExcel={handleDownloadExcel} label="Export Records" />
            </div>
        </div>

        <div className="overflow-x-auto bg-white rounded-2xl shadow-xl border border-slate-200 custom-scrollbar">
            <table className="min-w-full divide-y divide-slate-200 table-fixed">
                <thead className={`${getHeaderStyle()} text-white`}>
                    <tr>
                        <th className="w-[200px] px-6 py-5 text-left text-[10px] font-black uppercase tracking-widest sticky left-0 z-20 bg-inherit shadow-[2px_0_5px_rgba(0,0,0,0.1)]">Target Unit</th>
                        {definition.fields.map(f => (
                            <th key={f.key} className="px-6 py-5 text-left text-[10px] font-black uppercase tracking-widest min-w-[150px]">{f.label}</th>
                        ))}
                        <th className="w-[150px] px-6 py-5 text-left text-[10px] font-black uppercase tracking-widest">Status</th>
                        <th className="w-[150px] px-6 py-5 text-left text-[10px] font-black uppercase tracking-widest">Last Updated</th>
                        <th className="w-[120px] px-6 py-5 text-center text-[10px] font-black uppercase tracking-widest sticky right-0 z-20 bg-inherit shadow-[-2px_0_5px_rgba(0,0,0,0.1)]">Action</th>
                    </tr>
                </thead>
                <tbody className="bg-white divide-y divide-slate-100">
                    {displayedReports.map((report, idx) => (
                        <tr key={idx} className="hover:bg-slate-50 transition-colors">
                            <td className="px-6 py-4 text-sm font-bold text-slate-900 sticky left-0 z-10 bg-white group-hover:bg-slate-50 border-r border-slate-100">{report['LGU/BARANGAY']}</td>
                            {definition.fields.map(f => {
                                const val = report.details?.[f.key];
                                return (
                                    <td key={f.key} className="px-6 py-4 text-xs font-medium text-slate-600 truncate max-w-[250px]" title={String(val || '')}>
                                        {Array.isArray(val) ? `${val.length} File(s)` : String(val || '-')}
                                    </td>
                                );
                            })}
                            <td className="px-6 py-4"><StatusBadge status={report.STATUS} isOverdue={report.isOverdue} /></td>
                            <td className="px-6 py-4 text-[10px] font-black text-slate-400 uppercase tracking-tighter tabular-nums">{report['LAST UPDATED']}</td>
                            <td className="px-6 py-4 text-center sticky right-0 z-10 bg-white group-hover:bg-slate-50 border-l border-slate-100">
                                <ActionButton onClick={() => onEdit(report)} disabled={report.isLocked} status={report.STATUS} />
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    </div>
  );
};

export default DynamicReportTable;

