                                    <td className="px-2 py-4 text-center"><span className={`px-2 py-1 rounded-md text-xs font-bold ${bgClass}`}>{statusText}</span></td>
                                    <td className="px-2 py-4 text-center sticky right-0 bg-inherit border-l border-slate-100"><ActionButton onClick={() => onEdit(r)} disabled={r.isLocked} status={r.STATUS} /></td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

