/**
 * Specialized update for Kalinisan Weekly reports.
 * Matches on City, Barangay, AND Week Covered to avoid overwriting the wrong row.
 */
function updateKalinisanBrgyRow(city, brgy, week, ...dataFields) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sheet = ss.getSheetByName('Kalinisan Brgy');
  if (!sheet) throw new Error("Sheet 'Kalinisan Brgy' not found");

  const data = sheet.getDataRange().getValues();
  const searchCity = String(city || "").trim().toUpperCase();
  const searchBrgy = String(brgy || "").trim().toUpperCase();
  const searchWeek = String(week || "").trim();

  // Extract utility args from the end of the rest parameter array
  const extra = dataFields.pop();
  const webTimestamp = dataFields.pop();
  const folderId = dataFields.pop();

  const processedData = processIncomingData_(dataFields, folderId, city + "_" + brgy + "_" + week);
  const timestampCol = getTimestampColumnIndex_(sheet);

  for (let i = 1; i < data.length; i++) {
    const rowCity = String(data[i][0]).trim().toUpperCase();
    const rowBrgy = String(data[i][1]).trim().toUpperCase();
    const rowWeek = String(data[i][2]).trim(); // Column 3 is Week Covered

    if (rowCity === searchCity && rowBrgy === searchBrgy && rowWeek === searchWeek) {
      // Data fields start at column 3 in the arguments but index 2 in the sheet row.
      // However, week is also a field in our definition. 
      // We overwrite starting at Column 3 (index 2) with all fields including week.
      sheet.getRange(i + 1, 3, 1, processedData.length).setValues([[searchWeek, ...processedData.slice(1)]]);

      if (timestampCol !== -1) {
          sheet.getRange(i + 1, timestampCol).setValue(webTimestamp);
      }
      SpreadsheetApp.flush();
      return "Success";
    }
  }

  // Optional: If no match found for that week, append as new row instead of failing?
  // For now, following current logic of matching existing.
  throw new Error("Specific entry for '" + brgy + "' week '" + week + "' not found.");
}

