            let totalPoints = 0;
            let onTimeCount = 0;
            let lateCount = 0;
            let pendingCount = 0;

            const relevantReports = reports.filter(r => 
                r.details?.city?.toUpperCase() === selectedLgu.toUpperCase() &&
                r.details?.barangay?.toUpperCase() === brgy.toUpperCase()
            );

            REPORT_DEFINITIONS.forEach(def => {
                const report = relevantReports.find(r => r['REPORT TYPE'] === def.id);

                if (report) {
                    if (report.STATUS === 'Completed') {
                        // Check if it's late based on the isOverdue/Late flag computed in App.tsx
                        if (report.isOverdue || report.STATUS.toUpperCase() === 'LATE') {
                            totalPoints += 0.5;
