            return {
                barangay: brgy,
                totalPoints,
                onTimeCount,
                lateCount,
                pendingCount,
                maxPossible,
                percentage
            };
        });

        // Sort by Points Descending, then OnTime Count Descending
        return data.sort((a, b) => {
            if (b.totalPoints !== a.totalPoints) return b.totalPoints - a.totalPoints;
