interface SubmissionStatusViewProps {
    reports: Report[];
    categoryFilter: string;
    statusFilter: string;
    onNavigate: (def: ReportDefinition) => void;
    manualOverrides?: Record<string, 'locked' | 'unlocked' | null>;
