const CATEGORY_ORDER = ['Barangay', 'Weekly', 'Monthly', 'Quarterly', 'Semestral', 'Annual', 'Quality Policy'];

function getNextDeadlineDate(def: ReportDefinition): Date {
    const now = new Date();
    const year = now.getFullYear();
    const D = def.deadline.day;
    const frequency = def.deadline.frequency || def.category.toLowerCase();
    const timeline: Date[] = [];

    if (frequency === 'monthly' || def.category === 'Monthly') {
        for (let y = year - 1; y <= year + 1; y++) {
            for (let m = 0; m < 12; m++) timeline.push(new Date(y, m, D, 23, 59, 59));
        }
    } else if (frequency === 'quarterly' || def.category === 'Quarterly') {
        const months = def.deadline.months || [1, 4, 7, 10];
        for (let y = year - 1; y <= year + 1; y++) {
            months.forEach(m => timeline.push(new Date(y, m - 1, D, 23, 59, 59)));
        }
    } else if (frequency === 'weekly' || def.category === 'Weekly') {
        const start = new Date(year - 1, 0, 1);
        while(start.getDay() !== D) start.setDate(start.getDate() + 1);
        const end = new Date(year + 1, 11, 31);
        const current = new Date(start);
        while(current <= end) {
            timeline.push(new Date(current.getTime()));
            current.setDate(current.getDate() + 7);
        }
    } else {
        for (let y = year - 1; y <= year + 1; y++) timeline.push(new Date(y, 0, D, 23, 59, 59));
    }
    timeline.sort((a, b) => a.getTime() - b.getTime());
    return timeline.find(d => d >= now) || timeline[timeline.length - 1];
}

const SubmissionStatusView: React.FC<SubmissionStatusViewProps> = ({ reports, categoryFilter, statusFilter, onNavigate, manualOverrides = {} }) => {
    const [modalData, setModalData] = useState<{ title: string, list: string[] } | null>(null);

    const sortedDefinitions = useMemo(() => {
        let defs = REPORT_DEFINITIONS.filter(d => !d.isInventory);
        if (categoryFilter !== 'All') defs = defs.filter(d => d.category === categoryFilter);
        return defs.sort((a, b) => {
            const idxA = CATEGORY_ORDER.indexOf(a.category);
            const idxB = CATEGORY_ORDER.indexOf(b.category);
            const valA = idxA === -1 ? 999 : idxA;
            const valB = idxB === -1 ? 999 : idxB;
            if (valA !== valB) return valA - valB;
            return a.title.localeCompare(b.title);
        });
    }, [categoryFilter]);

    return (
        <>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-6 pb-12 animate-fade-in">
                {sortedDefinitions.map(def => {
                    const relevantReports = reports.filter(r => r['REPORT TYPE'] === def.id);
                    const isFullyCompliant = relevantReports.length > 0 && relevantReports.every(r => r.STATUS === 'Completed');
                    if (statusFilter === 'Completed' && !isFullyCompliant) return null;
                    if (statusFilter === 'Pending' && isFullyCompliant) return null;

                    return (
                        <ReportCard 
                            key={def.id} 
                            definition={def} 
                            reports={relevantReports} 
                            onNavigate={onNavigate} 
                            onViewPending={(list) => setModalData({ title: def.title, list })}
                            manualOverride={manualOverrides[def.id] || null}
                        />
                    );
                })}
            </div>

            {modalData && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
                    <div className="bg-white rounded-2xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden border border-white/20">
                        <div className="px-8 py-6 border-b border-slate-100 bg-slate-50/80 flex justify-between items-center shrink-0">
                            <div>
                                <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-1">Pending/Late Submissions</h4>
                                <h3 className="font-extrabold text-slate-800 text-2xl tracking-tight leading-tight">{modalData.title}</h3>
                            </div>
                            <button onClick={() => setModalData(null)} className="text-slate-400 hover:text-slate-600 bg-white border border-slate-200 p-2 rounded-full">
                                <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                            </button>
                        </div>
                        <div className="flex-1 overflow-y-auto p-6 bg-white">
                            {modalData.list.length > 0 ? (
                                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                                    {modalData.list.map((item, idx) => (
                                        <div key={idx} className="flex items-center text-slate-700 text-sm font-semibold p-3 rounded-xl bg-slate-50 border border-slate-100 hover:bg-amber-50">
                                            <span className="flex items-center justify-center w-8 h-8 rounded-lg bg-white border border-slate-200 text-amber-600 mr-3 shrink-0 text-xs font-bold">{idx + 1}</span>
                                            <span className="truncate" title={item}>{item}</span>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="flex flex-col items-center justify-center h-64 text-center px-6">
                                    <div className="w-20 h-20 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center mb-6 shadow-sm border border-emerald-100"><CheckIcon /></div>
                                    <p className="text-emerald-700 font-extrabold text-2xl">All Compliant!</p>
                                </div>
                            )}
                        </div>
                        <div className="px-8 py-5 border-t border-slate-100 bg-slate-50/50 text-right"><button onClick={() => setModalData(null)} className="px-6 py-3 bg-slate-800 text-white text-sm font-bold rounded-xl">Close</button></div>
                    </div>
                </div>
            )}
        </>
    );
};

const ReportCard: React.FC<{ 
    definition: ReportDefinition, 
    reports: Report[], 
    onNavigate: (def: ReportDefinition) => void,
    onViewPending: (list: string[]),
    manualOverride: 'locked' | 'unlocked' | null
}> = ({ definition, reports, onNavigate, onViewPending, manualOverride }) => {

    const stats = useMemo(() => {
        const total = reports.length || 1; 
        const done = reports.filter(r => r.STATUS === 'Completed').length;
        const pending = reports.filter(r => r.STATUS === 'Pending').length;
        const late = reports.filter(r => r.STATUS === 'Late').length;
        const percentage = total > 0 ? Math.round((done / total) * 100) : 0;

        let latest = '';
        reports.forEach(r => {
            const dateStr = r['LAST UPDATED'];
            if (dateStr && dateStr !== 'Legacy Data' && dateStr !== 'Not Submitted' && (!latest || new Date(dateStr) > new Date(latest))) {
                latest = dateStr;
            }
        });

        // The effective lock state considers manual override
        let isLocked = reports.length > 0 && reports.every(r => r.isLocked);
        if (manualOverride === 'unlocked') isLocked = false;
        else if (manualOverride === 'locked') isLocked = true;

        const windowStatus = reports[0]?.windowStatus || 'Waiting';
        const nextOpeningDate = reports[0]?.nextOpeningDate;

        return { total, done, pending, late, percentage, latest, isLocked, windowStatus, nextOpeningDate };
    }, [reports, manualOverride]);

    const deadlineDateObj = useMemo(() => getNextDeadlineDate(definition), [definition]);
    const formattedDeadline = useMemo(() => {
        return formatTimestamp(deadlineDateObj).split(' ')[0] + ' ' + formatTimestamp(deadlineDateObj).split(' ')[1]; 
    }, [deadlineDateObj]);

    const pendingList = useMemo(() => {
        if (reports.length === 0) return ['No current submission recorded'];
        return reports.filter(r => r.STATUS !== 'Completed').map(r => r['LGU/BARANGAY']).sort();
    }, [reports]);

    const getGradient = (category: string) => {
        if (category === 'Monthly') return 'from-blue-600 to-indigo-700';
        if (category === 'Quarterly') return 'from-orange-400 to-orange-600';
        if (category === 'Barangay') return 'from-indigo-600 to-purple-700';
        if (category === 'Weekly') return 'from-purple-500 to-pink-600';
        if (category === 'Quality Policy') return 'from-teal-500 to-emerald-700';
        if (category === 'Annual') return 'from-cyan-500 to-blue-700';
        return 'from-slate-600 to-slate-800';
    };

    const gradientClass = getGradient(definition.category);
    const isCompleted = stats.done === stats.total && stats.total > 0;
    const isLateAvailable = stats.late > 0 && !stats.isLocked;

    return (
        <div 
            onClick={() => onNavigate(definition)}
            className={`relative p-6 rounded-[28px] transition-all duration-300 ease-out hover:-translate-y-2 hover:shadow-2xl cursor-pointer bg-gradient-to-br ${gradientClass} text-white flex flex-col h-full overflow-hidden border-t border-white/20`}
        >
            <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at 2px 2px, white 2px, transparent 0)', backgroundSize: '16px 16px' }}></div>

            <div className="flex justify-between items-start mb-6">
                <div className="flex flex-col gap-2">
                    <span className="px-4 py-1.5 bg-white/20 backdrop-blur-md rounded-full text-[10px] font-black uppercase tracking-widest border border-white/10 w-fit">
                        {definition.category}
                    </span>
                    <div className="flex flex-col gap-1.5">
                        {manualOverride === 'unlocked' && (
                             <span className="px-4 py-1.5 bg-indigo-500/80 text-white backdrop-blur-md rounded-full text-[10px] font-black uppercase tracking-widest border border-white/20 w-fit flex items-center shadow-lg">
                                <svg className="w-3 h-3 mr-1.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 11V7a4 4 0 118 0m-4 8v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2z" /></svg>
                                Forced Unlock
                             </span>
                        )}
                        {manualOverride === 'locked' && (
                             <span className="px-4 py-1.5 bg-slate-900 text-white rounded-full text-[10px] font-black uppercase tracking-widest border border-white/20 w-fit flex items-center shadow-lg">
                                <svg className="w-3 h-3 mr-1.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                                Admin Lock
                             </span>
                        )}

                        {!manualOverride && stats.isLocked ? (
                            <>
                                <span className="px-4 py-1.5 bg-slate-900/40 backdrop-blur-md rounded-full text-[10px] font-black uppercase tracking-widest border border-white/10 w-fit flex items-center">
                                    <svg className="w-3 h-3 mr-1.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                                    Locked
                                </span>
                                {stats.nextOpeningDate && (
                                    <div className="flex items-center gap-1.5 px-2 text-[9px] font-black text-white/60 uppercase tracking-tighter">
                                        <svg className="w-2.5 h-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2-2v12a2 2 0 002 2z" /></svg>
                                        Opens: {stats.nextOpeningDate}
                                    </div>
                                )}
                            </>
                        ) : !manualOverride && isLateAvailable ? (
                            <span className="px-4 py-1.5 bg-rose-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg flex items-center w-fit animate-pulse">
                                <span className="w-1.5 h-1.5 bg-white rounded-full mr-2"></span> LATE SUBMISSION OPEN
                            </span>
                        ) : !manualOverride && (
                            <span className="px-4 py-1.5 bg-emerald-500 text-white rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg flex items-center w-fit animate-pulse">
                                <span className="w-1.5 h-1.5 bg-white rounded-full mr-2"></span> Open for Update
                            </span>
                        )}
                    </div>
                </div>
                <div className="flex flex-col items-end">
                    <span className="text-[10px] font-black uppercase tracking-widest text-white/70 mb-1">Target Deadline</span>
                    <div className="flex items-center gap-2 px-3 py-1.5 bg-white/20 backdrop-blur-md rounded-xl border border-white/10">
                        <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2-2v12a2 2 0 002 2z" /></svg>
                        <span className="text-xs font-bold">{formattedDeadline}</span>
                    </div>
                </div>
            </div>

            <h3 className="text-2xl font-black mb-1 leading-tight drop-shadow-sm">{definition.title}</h3>
            <div className="flex items-center mb-6 opacity-80">
                <span className="text-[10px] font-bold uppercase tracking-widest mr-2">Last Update:</span>
                <span className="text-[10px] font-black">{stats.latest || 'No Record'}</span>
            </div>

            <div className="bg-white rounded-2xl p-5 mb-6 shadow-inner text-slate-800">
                <div className="flex justify-between items-center mb-4">
                    <div className="flex flex-col">
                        <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest mb-1">Compliance</span>
                        <div className="flex items-baseline"><span className="text-2xl font-black">{stats.done}</span><span className="text-xs font-bold text-slate-400 ml-1">/ {stats.total}</span></div>
                    </div>
                    <div className="text-3xl font-black text-blue-600">{stats.percentage}%</div>
                    <div className="flex flex-col items-end gap-0.5">
                        <div className="flex items-center gap-2"><span className="text-[9px] font-bold text-slate-400 uppercase">Pending</span><span className="text-xs font-black text-amber-500">{stats.pending}</span></div>
                        <div className="flex items-center gap-2"><span className="text-[9px] font-bold text-slate-400 uppercase">Late</span><span className="text-xs font-black text-rose-500">{stats.late}</span></div>
                    </div>
                </div>
                <div className="w-full bg-slate-100 rounded-full h-3 overflow-hidden">
                    <div className={`h-full transition-all duration-1000 ease-out ${isCompleted ? 'bg-emerald-500' : isLateAvailable ? 'bg-rose-500' : 'bg-blue-600'}`} style={{ width: `${stats.percentage}%` }}></div>
                </div>
            </div>

            <div 
                className={`mt-auto flex items-center justify-between px-5 py-4 rounded-2xl backdrop-blur-md transition-all ${isCompleted ? 'bg-emerald-500/30 border border-emerald-400/30' : isLateAvailable ? 'bg-rose-500/20 border border-rose-400/30' : 'bg-slate-900/20 border border-white/10'}`}
                onClick={(e) => { e.stopPropagation(); onViewPending(pendingList); }}
            >
                <div className="flex items-center gap-3">
                    <span className={`w-2 h-2 rounded-full ${isCompleted ? 'bg-emerald-400 animate-pulse' : stats.isLocked ? 'bg-slate-400' : isLateAvailable ? 'bg-rose-400' : 'bg-amber-400'}`}></span>
                    <span className="text-xs font-black uppercase tracking-widest">
                        {isCompleted ? 'Fully Compliant' : stats.isLocked ? 'Window Closed' : isLateAvailable ? 'Action Required (Late)' : 'Pending Updates'}
                    </span>
                </div>
                <svg className="w-4 h-4 text-white/60" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
            </div>
        </div>
    );
};

export default SubmissionStatusView;

import React, { useState, useMemo } from 'react';
import { Report, ReportDefinition } from '../types';
import { StatusBadge, ActionButton } from './ReportsTable';
import ReportProgress from './ReportProgress';
import ExportMenu from './ExportMenu';
import { LGU_LIST } from '../services/dataService';

declare const XLSX: any;

interface DynamicReportTableProps {
  reports: Report[];
  definition: ReportDefinition;
  onEdit: (report: Report) => void;
  isProvince?: boolean;
  manualOverrideState?: 'locked' | 'unlocked' | null;
  onSetOverride?: (state: 'locked' | 'unlocked' | null) => void;
}

const DynamicReportTable: React.FC<DynamicReportTableProps> = ({ 
    reports, 
    definition, 
    onEdit, 
    isProvince,
    manualOverrideState = null,
    onSetOverride
}) => {
  const [viewFiles, setViewFiles] = useState<{ title: string, urls: string[] } | null>(null);
  const [lguFilter, setLguFilter] = useState<string>("All");

  const displayedReports = useMemo(() => {
      if (!isProvince || lguFilter === "All") return reports;
      return reports.filter(r => {
          const city = (r.details?.city || "").toUpperCase();
          return city === lguFilter.toUpperCase();
      });
  }, [reports, lguFilter, isProvince]);

  const handleDownloadPdf = () => {
      if (!(window as any).jspdf) return;
      const { jsPDF } = (window as any).jspdf;
      const doc = new jsPDF('l', 'mm', 'a4');
      const dateStr = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
      doc.setFontSize(12).text("DILG-SAMAR", 148.5, 15, { align: 'center' });
      const filterSuffix = isProvince && lguFilter !== "All" ? ` - ${lguFilter}` : "";
      doc.setFontSize(11).text(`Full Data Export: ${definition.title}${filterSuffix} as of ${dateStr}`, 148.5, 22, { align: 'center' });
      const headers = ['LGU/BARANGAY', ...definition.fields.map(f => f.label), 'STATUS', 'LAST UPDATED'];
      const data = displayedReports.map(report => {
          const row = [report['LGU/BARANGAY']];
          definition.fields.forEach(field => {
              let val = report.details?.[field.key];
              if (Array.isArray(val)) val = `${val.length} file(s) attached`;
              else if (typeof val === 'string' && val.startsWith('data:')) val = 'File Pending Upload';
              row.push(val || '');
          });
          row.push(report.STATUS);
          row.push(report['LAST UPDATED']);
          return row;
      });
      (doc as any).autoTable({ head: [headers], body: data, startY: 30, styles: { fontSize: 6, cellPadding: 1 }, headStyles: { fillColor: [30, 41, 59], textColor: 255 }, theme: 'grid' });
      doc.save(`${definition.title}${filterSuffix.replace(/\s+/g, '_')}_Export.pdf`);
  };

  const handleDownloadExcel = () => {
      if (typeof XLSX === 'undefined') return;
      const headers = ['LGU/BARANGAY', ...definition.fields.map(f => f.label), 'STATUS', 'LAST UPDATED'];
      const data = displayedReports.map(report => {
          const row = [report['LGU/BARANGAY']];
          definition.fields.forEach(field => {
              let val = report.details?.[field.key];
              if (Array.isArray(val)) val = val.join(', ');
              row.push(val || '');
          });
          row.push(report.STATUS);
          row.push(report['LAST UPDATED']);
          return row;
      });
      const ws = XLSX.utils.aoa_to_sheet([headers, ...data]);
      const wb = XLSX.utils.book_new();
      const filterSuffix = isProvince && lguFilter !== "All" ? `_${lguFilter}` : "";
      XLSX.utils.book_append_sheet(wb, ws, "Full Report Data");
      XLSX.writeFile(wb, `${definition.title}${filterSuffix.replace(/\s+/g, '_')}_Export.xlsx`);
  };

  const getHeaderStyle = () => {
    switch(definition.category) {
      case 'Monthly': return 'bg-gradient-to-r from-blue-700 to-blue-800';
      case 'Quarterly': return 'bg-gradient-to-r from-orange-600 to-orange-700';
      case 'Barangay': return 'bg-gradient-to-r from-indigo-600 to-indigo-800';
      default: return 'bg-gradient-to-r from-teal-700 to-teal-800';
    }
  };

  const getColumnClasses = (accessor: string) => {
      if (accessor === 'LGU/BARANGAY' || accessor === 'city' || accessor === 'barangay') return "w-[200px] min-w-[160px] text-slate-900 font-bold whitespace-normal align-top";
      return "min-w-[120px] whitespace-normal break-words text-slate-700 align-top";
  };

  return (
    <div className="space-y-6 animate-fade-in">
        <ReportProgress reports={displayedReports} category={definition.category} />

        {/* ADMIN OVERRIDE PANEL */}
        {isProvince && onSetOverride && (
            <div className="bg-slate-900 p-6 rounded-3xl border border-slate-800 shadow-2xl overflow-hidden relative group">
                <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at 2px 2px, white 2px, transparent 0)', backgroundSize: '16px 16px' }}></div>
                <div className="relative z-10 flex flex-col md:flex-row justify-between items-center gap-6">
                    <div className="flex items-center gap-4">
                        <div className="bg-blue-600/20 p-3 rounded-2xl border border-blue-500/30">
                            <svg className="w-6 h-6 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                        </div>
                        <div>
                            <h4 className="text-sm font-black text-white uppercase tracking-widest">Master Lock Override</h4>
                            <p className="text-xs text-slate-400 font-medium">Manually force this report open or closed across Samar.</p>
                        </div>
                    </div>

                    <div className="flex bg-slate-800 p-1.5 rounded-2xl border border-slate-700">
                        <button 
                            onClick={() => onSetOverride(null)}
                            className={`px-4 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${manualOverrideState === null ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                        >
                            Automatic
                        </button>
                        <button 
                            onClick={() => onSetOverride('locked')}
                            className={`px-4 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${manualOverrideState === 'locked' ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                        >
                            Force Lock
                        </button>
                        <button 
                            onClick={() => onSetOverride('unlocked')}
                            className={`px-4 py-2 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${manualOverrideState === 'unlocked' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400 hover:text-white'}`}
                        >
                            Force Unlock
                        </button>
                    </div>
                </div>
            </div>
        )}

        <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-white/50 p-4 rounded-2xl border border-slate-200">
            <div className="flex-1 w-full">
                {isProvince && (
                    <div className="flex items-center gap-3">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest whitespace-nowrap">Filter LGU Unit:</label>
                        <select value={lguFilter} onChange={(e) => setLguFilter(e.target.value)} className="bg-white border border-slate-200 rounded-xl px-4 py-2 text-xs font-bold outline-none focus:ring-2 focus:ring-blue-500 transition-all min-w-[200px] shadow-sm">
                            <option value="All">All Samar LGUs</option>
                            {LGU_LIST.map(lgu => <option key={lgu} value={lgu}>{lgu}</option>)}
                        </select>
                    </div>
                )}
            </div>
            <div className="flex items-center gap-3">
                <ExportMenu onExportPdf={handleDownloadPdf} onExportExcel={handleDownloadExcel} label="Export Full Data" />
            </div>
        </div>

        <div className="overflow-x-auto bg-white rounded-2xl shadow-md border border-slate-200">
        <table className="min-w-full divide-y divide-slate-100 table-fixed">
            <thead className={getHeaderStyle()}>
            <tr>
                {definition.columns.map((col) => (
                <th key={col.accessor} className={`px-4 py-5 text-left text-xs font-bold text-white uppercase tracking-wider ${getColumnClasses(col.accessor)} !text-white align-bottom opacity-90`}>
                    {col.header}
                </th>
                ))}
                <th className="px-4 py-5 text-center text-xs font-bold text-white uppercase tracking-wider w-[120px] min-w-[100px] sticky right-0 z-10 !text-white align-bottom shadow-xl" style={{backgroundColor: 'inherit'}}>Action</th>
            </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-100">
            {displayedReports.map((report, idx) => (
                <tr key={idx} className={`transition-colors duration-150 ${report.STATUS === 'Completed' ? 'bg-emerald-50/40 hover:bg-emerald-50/70' : (report.STATUS === 'Overdue' || report.STATUS === 'Late') ? 'bg-red-50/30 hover:bg-red-50/60' : 'hover:bg-slate-50'}`}>
                {definition.columns.map((col) => {
                    let val = (report as any)[col.accessor];
                    if (val === undefined && report.details) val = report.details[col.accessor];
                    return (
                    <td key={col.accessor} className={`px-4 py-4 text-sm ${getColumnClasses(col.accessor)}`}>
                        {col.type === 'link' && val ? (
                            (() => {
                                const valStr = Array.isArray(val) ? val.join(',') : String(val);
                                if (valStr.startsWith('data:')) return <div className="inline-flex items-center px-2 py-1 bg-amber-50 border border-amber-200 rounded text-[10px] text-amber-700 font-bold uppercase tracking-tighter"><span className="w-2 h-2 rounded-full bg-amber-400 mr-1.5 animate-pulse"></span>File Attached</div>;
                                const links = valStr.split(/[\n,]+/).filter((v: string) => v.trim().startsWith('http'));
                                if (links.length > 1) return <button onClick={() => setViewFiles({ title: report['LGU/BARANGAY'], urls: links })} className="inline-flex items-center justify-center text-blue-700 bg-blue-50 border border-blue-200 px-3 py-1.5 rounded-lg text-xs font-bold">View {links.length} Files</button>;
                                if (links.length === 1) return <a href={links[0].trim()} target="_blank" rel="noreferrer" className="text-blue-600 hover:text-blue-800 font-medium">View</a>;
                                return <span className="text-xs text-slate-400 italic">Pending Sync</span>;
                            })()
                        ) : col.type === 'badge' ? (
                        <StatusBadge status={report.STATUS} isOverdue={report.isOverdue} />
                        ) : (
                        <span>{val}</span>
                        )}
                    </td>
                    );
                })}
                <td className="px-4 py-4 whitespace-nowrap text-sm font-medium align-middle sticky right-0 bg-inherit border-l border-slate-100 text-center">
                    <ActionButton onClick={() => onEdit(report)} disabled={report.isLocked} status={report.STATUS} />
                </td>
                </tr>
            ))}
            </tbody>
        </table>
        </div>

        {viewFiles && (
            <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/70 backdrop-blur-sm p-4 animate-fade-in">
                <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md max-h-[80vh] flex flex-col overflow-hidden border border-white/20">
                    <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                        <div>
                            <h3 className="font-bold text-slate-800 text-lg">Attached Files</h3>
                            <p className="text-xs text-slate-500">{viewFiles.title}</p>
                        </div>
                        <button onClick={() => setViewFiles(null)} className="text-slate-400 hover:text-slate-600 bg-white rounded-full p-1 border border-slate-200">
                            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                    </div>
                    <div className="p-4 overflow-y-auto flex-1 bg-slate-50/30">
                        <div className="space-y-2">
                            {viewFiles.urls.map((url, i) => (
                                <a key={i} href={url} target="_blank" rel="noreferrer" className="flex items-center p-3 bg-white border border-slate-200 rounded-xl hover:border-blue-400 hover:shadow-md transition-all group">
                                    <div className="bg-blue-100 text-blue-600 p-2 rounded-lg mr-3 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                                        <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" /></svg>
                                    </div>
                                    <div className="flex-1">
                                        <p className="text-sm font-bold text-slate-700 group-hover:text-blue-700">File {i + 1}</p>
                                        <p className="text-[10px] text-slate-400 truncate max-w-[200px]">{url}</p>
                                    </div>
                                </a>
                            ))}
                        </div>
                    </div>
                    <div className="px-6 py-4 border-t border-slate-100 bg-white text-right"><button onClick={() => setViewFiles(null)} className="px-5 py-2 bg-slate-800 text-white text-sm font-bold rounded-xl">Close</button></div>
                </div>
            </div>
        )}
    </div>
  );
};

export default DynamicReportTable;

import React, { useMemo, useState } from 'react';
import { Report, ReportDefinition } from '../types';
import { REPORT_DEFINITIONS, BARANGAY_LEVEL_REPORT_IDS } from '../reportDefinitions';
import ExportMenu from './ExportMenu';

declare const XLSX: any;

interface ProvinceSummaryViewProps {
  reports: Report[];
  lgus: string[];
  barangaysMap: Record<string, string[]>;
}

const ProvinceSummaryView: React.FC<ProvinceSummaryViewProps> = ({ reports, lgus, barangaysMap }) => {
  const [selectedLgu, setSelectedLgu] = useState<string>(lgus[0] || "");
  const [searchTerm, setSearchTerm] = useState("");

  const currentBarangays = useMemo(() => {
    return barangaysMap[selectedLgu] || [];
  }, [selectedLgu, barangaysMap]);

  const tallyData = useMemo(() => {
    if (!selectedLgu) return [];

    return currentBarangays.map(brgy => {
      const row: any = { barangay: brgy };

      REPORT_DEFINITIONS.forEach(def => {
        const report = reports.find(r => 
          r['REPORT TYPE'] === def.id && 
          r.details?.city?.toUpperCase() === selectedLgu.toUpperCase() &&
          r.details?.barangay?.toUpperCase() === brgy.toUpperCase()
        );

        row[def.id] = {
          status: report ? report.STATUS : 'Pending',
          updated: report ? report['LAST UPDATED'] : 'Never',
          summary: report ? report['DATA SUMMARY'] : 'No data'
        };
      });

      return row;
    });
  }, [reports, selectedLgu, currentBarangays]);

  const filteredData = useMemo(() => {
    if (!searchTerm) return tallyData;
    const term = searchTerm.toLowerCase();
    return tallyData.filter(d => d.barangay.toLowerCase().includes(term));
  }, [tallyData, searchTerm]);

  const handleExportPdf = () => {
    if (!(window as any).jspdf) return;
    const { jsPDF } = (window as any).jspdf;
    const doc = new jsPDF('l', 'mm', 'a4');

    doc.setFontSize(16);
    doc.setTextColor(30, 41, 59);
    doc.text(`SUBMISSION TALLY: ${selectedLgu}`, 148.5, 15, { align: 'center' });

    doc.setFontSize(10);
    doc.text(`Generated on ${new Date().toLocaleString()}`, 148.5, 22, { align: 'center' });

    const headers = [['Barangay', ...REPORT_DEFINITIONS.map(d => d.id)]];
    const body = filteredData.map(row => [
      row.barangay,
      ...REPORT_DEFINITIONS.map(def => row[def.id].status)
    ]);

    (doc as any).autoTable({
      head: headers,
      body: body,
      startY: 30,
      styles: { fontSize: 6, cellPadding: 1.5 },
      headStyles: { fillColor: [15, 23, 42], textColor: 255 },
      columnStyles: {
        0: { fontStyle: 'bold', fillColor: [248, 250, 252] }
      },
      theme: 'grid'
    });

    doc.save(`Tally_${selectedLgu.replace(/\s+/g, '_')}.pdf`);
  };

  const handleExportExcel = () => {
    if (typeof XLSX === 'undefined') return;
    const headers = ['Barangay', ...REPORT_DEFINITIONS.map(d => d.id)];
    const body = filteredData.map(row => [
      row.barangay,
      ...REPORT_DEFINITIONS.map(def => row[def.id].status)
    ]);

    const ws = XLSX.utils.aoa_to_sheet([headers, ...body]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Barangay Tally");
    XLSX.writeFile(wb, `Tally_${selectedLgu.replace(/\s+/g, '_')}.xlsx`);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm flex flex-col md:flex-row justify-between items-end gap-6">
        <div className="w-full md:w-1/3">
          <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Select LGU Unit</label>
          <select 
            value={selectedLgu}
            onChange={(e) => setSelectedLgu(e.target.value)}
            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold shadow-sm focus:ring-2 focus:ring-blue-500 outline-none transition-all"
          >
            {lgus.map(lgu => (
              <option key={lgu} value={lgu}>{lgu}</option>
            ))}
          </select>
        </div>

        <div className="flex-1 flex gap-4 w-full md:w-auto">
          <div className="relative flex-1">
             <input 
              type="text" 
              placeholder="Filter Barangay..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-4 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            />
          </div>
          <ExportMenu onExportPdf={handleExportPdf} onExportExcel={handleExportExcel} label="Export LGU Tally" />
        </div>
      </div>

      <div className="bg-white rounded-3xl border border-slate-200 shadow-2xl overflow-hidden">
        {/* Extended Height: Changed from max-h-[70vh] to max-h-[85vh] for a more expansive view */}
        <div className="overflow-auto custom-scrollbar max-h-[85vh] shadow-inner bg-slate-50/20">
          <table className="min-w-full divide-y divide-slate-100 border-separate border-spacing-0">
            <thead className="bg-slate-900 text-white sticky top-0 z-[60] shadow-md">
              <tr>
                {/* Intersection Cell: Top-0 and Left-0 with highest z-index */}
                <th className="px-6 py-5 text-left text-[10px] font-black uppercase tracking-widest sticky left-0 top-0 bg-slate-900 z-[70] border-r border-slate-800">
                  Barangay
                </th>
                {REPORT_DEFINITIONS.map(def => (
                  <th key={def.id} className="px-4 py-5 text-center text-[9px] font-black uppercase tracking-tighter truncate max-w-[120px] whitespace-nowrap sticky top-0 bg-slate-900 z-[60]" title={def.title}>
                    {def.id}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {filteredData.length === 0 ? (
                <tr>
                  <td colSpan={REPORT_DEFINITIONS.length + 1} className="px-6 py-20 text-center text-slate-400 font-bold uppercase tracking-widest text-xs italic">
                    No records found for the selected LGU
                  </td>
                </tr>
              ) : (
                filteredData.map((row, i) => (
                  <tr key={i} className="hover:bg-slate-50 transition-colors group">
                    <td className="px-6 py-4 text-xs font-black text-slate-700 sticky left-0 bg-white z-20 border-r border-slate-100 group-hover:bg-slate-50 shadow-[1px_0_4px_rgba(0,0,0,0.05)]">
                      {row.barangay}
                    </td>
                    {REPORT_DEFINITIONS.map(def => {
                      const data = row[def.id];
                      const isCompleted = data.status === 'Completed';
                      return (
                        <td key={def.id} className="px-4 py-4 text-center border-r border-slate-50 last:border-0">
                          <div className="flex flex-col items-center group/cell relative">
                            <span className={`w-3 h-3 rounded-full shadow-sm transition-transform group-hover/cell:scale-125 ${isCompleted ? 'bg-emerald-500 ring-4 ring-emerald-500/10' : 'bg-slate-200 opacity-60'}`}></span>
                            <span className={`mt-2 text-[8px] font-black uppercase tracking-tighter ${isCompleted ? 'text-emerald-600' : 'text-slate-300'}`}>
                              {isCompleted ? 'Done' : 'Pending'}
                            </span>

                            {/* Tooltip on hover */}
                            <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-48 bg-slate-800 text-white p-3 rounded-xl shadow-2xl z-[80] opacity-0 group-hover/cell:opacity-100 transition-opacity pointer-events-none text-left">
                               <p className="text-[10px] font-black border-b border-white/10 pb-1 mb-1">{def.title}</p>
                               <p className="text-[9px] font-medium opacity-80 leading-relaxed truncate">{data.summary}</p>
                               <p className="text-[8px] font-black text-slate-400 mt-2">UPDATED: {data.updated}</p>
                            </div>
                          </div>
                        </td>
                      );
                    })}
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-8">
        <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
          <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Color Guide</h4>
          <div className="space-y-3">
            <div className="flex items-center gap-3">
              <span className="w-3 h-3 rounded-full bg-emerald-500"></span>
              <span className="text-sm font-bold text-slate-700">Submitted (Completed)</span>
            </div>
            <div className="flex items-center gap-3">
              <span className="w-3 h-3 rounded-full bg-slate-200"></span>
              <span className="text-sm font-bold text-slate-700">Not Yet Submitted (Pending)</span>
            </div>
          </div>
        </div>
        <div className="bg-slate-900 p-6 rounded-3xl text-white shadow-xl flex flex-col justify-center">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Information</p>
          <p className="text-sm font-medium leading-relaxed italic opacity-80">
            "This table shows the real-time status of all required reports for each barangay in {selectedLgu}. Both headers and the barangay column are fixed for easier navigation."
          </p>
        </div>
      </div>
    </div>
  );
};

